import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { transformExtractionProviderHandler } from '../../handlers/ts/surface/providers/transform-extraction-provider.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

describe('TransformExtractionProvider functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('analyze', () => {
    it('builds a valid StorageProgram', () => {
      const program = transformExtractionProviderHandler.analyze({ program: 'test-program' });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = transformExtractionProviderHandler.analyze({ program: 'test-program' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('covers all declared variants', () => {
      const program = transformExtractionProviderHandler.analyze({ program: 'test-program' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = extractCompletionVariants(program);
      expect(variants).toContain('ok');
      expect(variants).toContain('error');
    });

    it('declares read and write sets', () => {
      const program = transformExtractionProviderHandler.analyze({ program: 'test-program' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = transformExtractionProviderHandler.analyze({ program: 'test-program' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes successfully', async () => {
      if (typeof transformExtractionProviderHandler.analyze !== 'function') return;
      const result = await interpret(transformExtractionProviderHandler.analyze({ program: 'test-program' }), storage);
      expect(result).toBeDefined();
      expect(result.variant).toBeDefined();
      expect(typeof result.variant).toBe('string');
    });

  });

  describe('invariant examples', () => {
    it("analyze extracts two applied transforms", async () => {
      const storage = createInMemoryStorage();
      const analyzeResult0 = await interpret(transformExtractionProviderHandler.analyze({ program: {"type":"literal","value":"{\"instructions\":[],\"appliedTransforms\":[\"dark-theme\",\"high-contrast\"]}"} }), storage);
      expect(analyzeResult0.variant).toBe("ok");
      const result = analyzeResult0.output["result"];
      const appliedTransforms = analyzeResult0.output["appliedTransforms"];
      const transformCount = analyzeResult0.output["transformCount"];
    });

    it("analyze returns zero for no transforms", async () => {
      const storage = createInMemoryStorage();
      const analyzeResult0 = await interpret(transformExtractionProviderHandler.analyze({ program: {"type":"literal","value":"{\"instructions\":[]}"} }), storage);
      expect(analyzeResult0.variant).toBe("ok");
      const result = analyzeResult0.output["result"];
      const appliedTransforms = analyzeResult0.output["appliedTransforms"];
      const transformCount = analyzeResult0.output["transformCount"];
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: transformCount equals length of appliedTransforms', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('analyze'), input: fc.record({ program: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = transformExtractionProviderHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(transformExtractionProviderHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: transformCount is negative', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('analyze'), input: fc.record({ program: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = transformExtractionProviderHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(transformExtractionProviderHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
                // Never: transformCount is negative
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

  describe('action contracts (PBT)', () => {
  });

});
